import subprocess
import os

def generate_lock_file(pipfile_path, requirements_path):
    """
    Generate a lock file for the project dependencies.
    
    Args:
        pipfile_path (str): Path to the Pipfile.
        requirements_path (str): Path to the requirements.txt file.
        
    Returns:
        str: The path to the generated lock file.
    """
    # Check if Pipfile exists
    if not os.path.exists(pipfile_path):
        raise FileNotFoundError("Pipfile not found.")
    
    # Generate a lock file using pip-compile
    subprocess.run(["pip-compile", "--output-file", "requirements.lock", requirements_path])
    
    return "requirements.lock"

def update_lock_file(lock_file_path, new_requirements_path):
    """
    Update the existing lock file with new dependencies.
    
    Args:
        lock_file_path (str): Path to the existing lock file.
        new_requirements_path (str): Path to the updated requirements.txt file.
        
    Returns:
        str: The path to the updated lock file.
    """
    # Check if the lock file exists
    if not os.path.exists(lock_file_path):
        raise FileNotFoundError("Lock file not found.")
    
    # Update the existing lock file using pip-compile
    subprocess.run(["pip-compile", "--output-file", "requirements.lock", new_requirements_path])
    
    return "requirements.lock"

def manage_dependencies(pipfile_path, requirements_path):
    """
    Manage project dependencies by generating or updating a lock file.
    
    Args:
        pipfile_path (str): Path to the Pipfile.
        requirements_path (str): Path to the requirements.txt file.
        
    Returns:
        str: The path to the generated or updated lock file.
    """
    # Check if both files exist
    if not os.path.exists(pipfile_path) and not os.path.exists(requirements_path):
        raise FileNotFoundError("Either Pipfile or requirements.txt not found.")
    
    # Generate a new lock file if it doesn't exist
    if not os.path.exists("requirements.lock"):
        return generate_lock_file(pipfile_path, requirements_path)
    
    # Update the existing lock file with new dependencies
    return update_lock_file("requirements.lock", requirements_path)

# Usage example:
lock_file = manage_dependencies("Pipfile", "requirements.txt")
print(f"Lock file generated: {lock_file}")